<!DOCTYPE html><html lang="es"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Gestión de Pagos</title><link rel="stylesheet" href="<?=BASE_URL?>/public/css/estilos.css"><link rel="stylesheet" href="<?=BASE_URL?>/public/css/admin.css"></head><body class="admin-page"><?php require __DIR__.'/../partials/navbar.php';?><div class="admin-layout"><?php require __DIR__.'/../partials/sidebar.php';?><div class="admin-sidebar-overlay" id="admin-sidebar-overlay" hidden></div><main class="admin-main"><header class="admin-payment-header"><div><h1>Gestión de Pagos</h1><p>Consulta, registra y valida los pagos del portal.</p></div><a class="admin-quick-action" href="<?=BASE_URL?>/index.php?ruta=admin-pago-manual">Registrar pago manual</a></header><?php require __DIR__.'/../../partials/flash.php';?><form class="admin-payment-toolbar"><input type="hidden" name="ruta" value="admin-pagos"><input name="buscar" value="<?=htmlspecialchars($b,ENT_QUOTES,'UTF-8')?>" placeholder="Buscar"><input type="month" name="periodo" value="<?=htmlspecialchars($p,ENT_QUOTES,'UTF-8')?>"><select name="estado"><option value="">Todos los estados</option><?php foreach(['Pendiente','Validado','Rechazado'] as $x):?><option <?=$e===$x?'selected':''?>><?=$x?></option><?php endforeach;?></select><select name="origen"><option value="">Todos los orígenes</option><?php foreach(['Portal Alumno','Manual Administrador'] as $x):?><option <?=$o===$x?'selected':''?>><?=$x?></option><?php endforeach;?></select><button>Filtrar</button></form><div class="admin-payment-table-wrap"><table class="admin-payment-table"><thead><tr><th>Folio</th><th>Matrícula</th><th>Alumno</th><th>Periodo</th><th>Método</th><th>Importe</th><th>Fecha</th><th>Origen</th><th>Estado</th><th>Acciones</th></tr></thead><tbody><?php foreach($pagos as $x):?><tr><td><?=htmlspecialchars($x['folio'],ENT_QUOTES,'UTF-8')?></td><td><?=htmlspecialchars($x['matricula']??'',ENT_QUOTES,'UTF-8')?></td><td><?=htmlspecialchars($x['alumno']??'',ENT_QUOTES,'UTF-8')?></td><td><?=htmlspecialchars(PeriodoHelper::formatear($x['periodo']),ENT_QUOTES,'UTF-8')?></td><td><?=htmlspecialchars($x['metodo_pago'],ENT_QUOTES,'UTF-8')?></td><td>$<?=number_format((float)$x['total_pagado'],2)?></td><td><?=htmlspecialchars($x['fecha_pago'],ENT_QUOTES,'UTF-8')?></td><td><?=htmlspecialchars($x['origen'],ENT_QUOTES,'UTF-8')?></td><td><span class="admin-payment-status admin-payment-status-<?=strtolower($x['estado_validacion'])?>"><?=htmlspecialchars($x['estado_validacion'],ENT_QUOTES,'UTF-8')?></span></td><td><a href="<?=BASE_URL?>/index.php?ruta=admin-pago-ver&amp;id=<?=(int)$x['id_pago']?>">Ver</a></td></tr><?php endforeach;?></tbody></table></div><nav class="admin-payment-pagination"><span>Total: <?=$total?></span><span>Página <?=$pg?> de <?=$paginas?></span></nav><?php require __DIR__.'/../partials/footer.php';?></main></div><script src="<?=BASE_URL?>/public/js/admin.js"></script></body></html>
